mapper.select:
SELECT r.id, r.resource_uuid, r.space_id, r.parent_id, r.resource_type, r.name, r.name_normalized, r.extension, r.size_bytes, r.object_id, r.path_cache, r.owner_user_id, r.is_deleted, r.deleted_at, r.created_at, r.updated_at FROM resources r JOIN users u ON r.owner_user_id = u.id WHERE u.user_uuid = #{userUuid} AND r.parent_id = #{parentId} AND r.is_deleted = 0
AND r.name_normalized LIKE CONCAT('%', #{keyword}, '%')
ORDER BY CASE WHEN r.resource_type = 'folder' THEN 0 ELSE 1 END ASC, r.name_normalized ASC, r.id ASC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM resources
WHERE parent_id = #{parentId}
  AND name_normalized = #{nameNormalized}
  AND is_deleted = 0

SELECT COUNT(1)
FROM resources
WHERE parent_id = #{parentId}
  AND name_normalized = #{nameNormalized}
  AND id != #{excludeId}
  AND is_deleted = 0

SELECT r.resource_uuid AS resourceUuid, r.name, r.resource_type AS resourceType, r.extension, r.size_bytes AS sizeBytes, r.updated_at AS updatedAt, e.deleted_at AS deletedAt, e.purge_at AS purgeAt, op.resource_uuid AS originalParentUuid FROM recycle_entries e INNER JOIN resources r ON r.id = e.resource_id INNER JOIN users u ON r.owner_user_id = u.id LEFT JOIN resources op ON op.id = e.original_parent_id WHERE u.user_uuid = #{userUuid} AND e.restored_at IS NULL AND r.is_deleted = 1
AND r.name_normalized LIKE CONCAT('%', #{keyword}, '%')
ORDER BY e.deleted_at DESC, r.id DESC LIMIT #{offset}, #{pageSize}

SELECT COUNT(1)
FROM resources
WHERE object_id = #{objectId}

mapper.delete:
DELETE
FROM resources
WHERE id = #{id}
  AND owner_user_id = #{ownerUserId}
